import fs from 'node:fs';
import path from 'node:path';

const rawVersion = process.argv[2];

if(!rawVersion){
    console.error('Missing semantic version argument.');
    process.exit(1);
}

const match = rawVersion.match(/^(\d+)\.(\d+)\.(\d+)(?:-([0-9A-Za-z.-]+))?$/);
if(!match){
    console.error(`Invalid semantic version: ${rawVersion}`);
    process.exit(1);
}

const [, major, minor, patch, prerelease = ''] = match;
const buildDate = new Date().toISOString();

// ── Root version.js ──
const versionTarget = path.resolve(process.cwd(), 'version.js');
const nextContent = `export const SITE_SEMVER = {
  major: ${Number(major)},
  minor: ${Number(minor)},
  patch: ${Number(patch)},
  prerelease: '${prerelease}',
  buildDate: '${buildDate}',
};

export function getVersion() {
  const { major, minor, patch, prerelease } = SITE_SEMVER;
  const base = \`${'${major}'}.${'${minor}'}.${'${patch}'}\`;
  return prerelease ? \`${'${base}'}-${'${prerelease}'}\` : base;
}

export function getBuildDate() {
  return SITE_SEMVER.buildDate || '';
}
`;
fs.writeFileSync(versionTarget, nextContent, 'utf8');
console.log(`Updated ${versionTarget} -> ${rawVersion}`);

// ── times-up/version.js ──
const timesUpVersionTarget = path.resolve(process.cwd(), 'times-up/version.js');
const timesUpVersionContent = `// This file is auto-generated by .github/scripts/sync-match3-version.mjs
// It mirrors root /version.js so that the times-up SW module can import it.
export const SITE_SEMVER = {
  major: ${Number(major)},
  minor: ${Number(minor)},
  patch: ${Number(patch)},
  prerelease: '${prerelease}',
  buildDate: '${buildDate}',
};

export function getVersion() {
  const { major, minor, patch, prerelease } = SITE_SEMVER;
  const base = \`${'${major}'}.${'${minor}'}.${'${patch}'}\`;
  return prerelease ? \`${'${base}'}-${'${prerelease}'}\` : base;
}

export function getBuildDate() {
  return SITE_SEMVER.buildDate || '';
}
`;
fs.writeFileSync(timesUpVersionTarget, timesUpVersionContent, 'utf8');
console.log(`Updated ${timesUpVersionTarget} -> ${rawVersion}`);

// ── flash-guess/version.js (Capacitor bundle mirror of root version.js) ──
const flashGuessVersionTarget = path.resolve(process.cwd(), 'flash-guess/version.js');
const flashGuessVersionContent = `// This file is auto-generated by .github/scripts/sync-match3-version.mjs
// It mirrors root /version.js so that Capacitor (webDir: flash-guess) can bundle it.
export const SITE_SEMVER = {
  major: ${Number(major)},
  minor: ${Number(minor)},
  patch: ${Number(patch)},
  prerelease: '${prerelease}',
  buildDate: '${buildDate}',
};

export function getVersion() {
  const { major, minor, patch, prerelease } = SITE_SEMVER;
  const base = \`${'${major}'}.${'${minor}'}.${'${patch}'}\`;
  return prerelease ? \`${'${base}'}-${'${prerelease}'}\` : base;
}

export function getBuildDate() {
  return SITE_SEMVER.buildDate || '';
}
`;
fs.writeFileSync(flashGuessVersionTarget, flashGuessVersionContent, 'utf8');
console.log(`Updated ${flashGuessVersionTarget} -> ${rawVersion}`);

// ── flash-guess/sw.js — CACHE version ──
const fgSwTarget = path.resolve(process.cwd(), 'flash-guess/sw.js');
let fgSwContent = fs.readFileSync(fgSwTarget, 'utf8');
fgSwContent = fgSwContent.replace(
  /^const CACHE = 'flashguess-v[^']+';$/m,
  `const CACHE = 'flashguess-v${Number(major)}.${Number(minor)}.${Number(patch)}';`
);
fs.writeFileSync(fgSwTarget, fgSwContent, 'utf8');
console.log(`Updated flash-guess/sw.js CACHE -> flashguess-v${rawVersion}`);

// ── times-up/sw.js — CACHE version ──
const tuSwTarget = path.resolve(process.cwd(), 'times-up/sw.js');
let tuSwContent = fs.readFileSync(tuSwTarget, 'utf8');
tuSwContent = tuSwContent.replace(
  /^const CACHE = 'timesup-v[^']+';$/m,
  `const CACHE = 'timesup-v${Number(major)}.${Number(minor)}.${Number(patch)}';`
);
fs.writeFileSync(tuSwTarget, tuSwContent, 'utf8');
console.log(`Updated times-up/sw.js CACHE -> timesup-v${rawVersion}`);

